/// Record models for the goat (caprine) module.
///
/// All dates are ISO 8601 strings (YYYY-MM-DD). Numeric IDs are stable
/// string identifiers generated by the data layer.

// ── Weight ────────────────────────────────────────────────────────────────────

class WeightRecord {
  const WeightRecord({
    required this.id,
    required this.animalId,
    required this.date,
    required this.weightKg,
    this.bodyConditionScore,
    this.notes,
  });

  final String id;
  final String animalId;
  final String date;
  final double weightKg;
  final double? bodyConditionScore;
  final String? notes;

  factory WeightRecord.fromJson(Map<String, dynamic> j) => WeightRecord(
        id: j['id'] as String,
        animalId: j['animalId'] as String,
        date: j['date'] as String,
        weightKg: (j['weightKg'] as num).toDouble(),
        bodyConditionScore: (j['bodyConditionScore'] as num?)?.toDouble(),
        notes: j['notes'] as String?,
      );

  Map<String, dynamic> toJson() => {
        'id': id,
        'animalId': animalId,
        'date': date,
        'weightKg': weightKg,
        if (bodyConditionScore != null)
          'bodyConditionScore': bodyConditionScore,
        if (notes != null) 'notes': notes,
      };
}

