// ── Kidding ───────────────────────────────────────────────────────────────────

class KiddingEvent {
  const KiddingEvent({
    required this.id,
    required this.damId,
    required this.kiddingDate,
    required this.totalKidsBorn,
    required this.kidsAliveBorn,
    required this.kidsStillborn,
    required this.birthWeights,
    required this.kidIds,
    required this.assisted,
    this.complications,
    this.notes,
  });

  final String id;
  final String damId;
  final String kiddingDate;
  final int totalKidsBorn;
  final int kidsAliveBorn;
  final int kidsStillborn;
  final List<double?> birthWeights;
  final List<String> kidIds;
  final bool assisted;
  final String? complications;
  final String? notes;

  factory KiddingEvent.fromJson(Map<String, dynamic> j) => KiddingEvent(
        id: j['id'] as String,
        damId: j['damId'] as String,
        kiddingDate: j['kiddingDate'] as String,
        totalKidsBorn: j['totalKidsBorn'] as int,
        kidsAliveBorn: j['kidsAliveBorn'] as int,
        kidsStillborn: j['kidsStillborn'] as int,
        birthWeights: (j['birthWeights'] as List<dynamic>)
            .map((e) => (e as num?)?.toDouble())
            .toList(),
        kidIds: (j['kidIds'] as List<dynamic>).cast<String>(),
        assisted: j['assisted'] as bool? ?? false,
        complications: j['complications'] as String?,
        notes: j['notes'] as String?,
      );

  Map<String, dynamic> toJson() => {
        'id': id,
        'damId': damId,
        'kiddingDate': kiddingDate,
        'totalKidsBorn': totalKidsBorn,
        'kidsAliveBorn': kidsAliveBorn,
        'kidsStillborn': kidsStillborn,
        'birthWeights': birthWeights,
        'kidIds': kidIds,
        'assisted': assisted,
        if (complications != null) 'complications': complications,
        if (notes != null) 'notes': notes,
      };
}

