// ── Medication log ────────────────────────────────────────────────────────────

class GoatMedicationLog {
  const GoatMedicationLog({
    required this.id,
    required this.animalId,
    required this.date,
    required this.drug,
    required this.dose,
    required this.route,
    this.reason,
    this.withdrawalDays,
    this.administeredBy,
    this.notes,
  });

  final String id;
  final String animalId;
  final String date;
  final String drug;
  final String dose;
  /// One of: oral / injection / topical / pour-on
  final String route;
  final String? reason;
  final int? withdrawalDays;
  final String? administeredBy;
  final String? notes;

  /// ISO date of the last withdrawal day, or null if none.
  String? get withdrawalExpiryDate {
    if (withdrawalDays == null || withdrawalDays == 0) return null;
    try {
      final start = DateTime.parse(date);
      return start
          .add(Duration(days: withdrawalDays!))
          .toIso8601String()
          .substring(0, 10);
    } catch (_) {
      return null;
    }
  }

  factory GoatMedicationLog.fromJson(Map<String, dynamic> j) =>
      GoatMedicationLog(
        id: j['id'] as String,
        animalId: j['animalId'] as String,
        date: j['date'] as String,
        drug: j['drug'] as String,
        dose: j['dose'] as String,
        route: j['route'] as String,
        reason: j['reason'] as String?,
        withdrawalDays: j['withdrawalDays'] as int?,
        administeredBy: j['administeredBy'] as String?,
        notes: j['notes'] as String?,
      );

  Map<String, dynamic> toJson() => {
        'id': id,
        'animalId': animalId,
        'date': date,
        'drug': drug,
        'dose': dose,
        'route': route,
        if (reason != null) 'reason': reason,
        if (withdrawalDays != null) 'withdrawalDays': withdrawalDays,
        if (administeredBy != null) 'administeredBy': administeredBy,
        if (notes != null) 'notes': notes,
      };
}

// ── Vaccination ───────────────────────────────────────────────────────────────

class GoatVaccination {
  const GoatVaccination({
    required this.id,
    required this.animalId,
    required this.vaccineName,
    required this.dueDate,
    this.givenDate,
    this.batchNumber,
    this.nextDueDate,
    this.administeredBy,
  });

  final String id;
  final String animalId;
  final String vaccineName;
  final String dueDate;
  final String? givenDate;
  final String? batchNumber;
  final String? nextDueDate;
  final String? administeredBy;

  bool get isOverdue {
    if (givenDate != null) return false;
    try {
      return DateTime.parse(dueDate).isBefore(DateTime.now());
    } catch (_) {
      return false;
    }
  }

  bool get isGiven => givenDate != null;

  factory GoatVaccination.fromJson(Map<String, dynamic> j) => GoatVaccination(
        id: j['id'] as String,
        animalId: j['animalId'] as String,
        vaccineName: j['vaccineName'] as String,
        dueDate: j['dueDate'] as String,
        givenDate: j['givenDate'] as String?,
        batchNumber: j['batchNumber'] as String?,
        nextDueDate: j['nextDueDate'] as String?,
        administeredBy: j['administeredBy'] as String?,
      );

  Map<String, dynamic> toJson() => {
        'id': id,
        'animalId': animalId,
        'vaccineName': vaccineName,
        'dueDate': dueDate,
        if (givenDate != null) 'givenDate': givenDate,
        if (batchNumber != null) 'batchNumber': batchNumber,
        if (nextDueDate != null) 'nextDueDate': nextDueDate,
        if (administeredBy != null) 'administeredBy': administeredBy,
      };
}

